import { Route,Routes } from 'react-router-dom';
import './App.css';
import Button from '@mui/material/Button';
import { Home } from './Pages/Home';

function App() {
  return (
    <div className="App">
      <h1>Hello world</h1>
      <Button variant="contained">Hello world</Button>

      <Routes>
      <Route path='/' element={<Home/>}/>
      </Routes>

    </div>
  );
}

export default App;
